import{_ as l}from"./DVjgo_Ss.js";import{_ as d,T as i,c as _,a as v,b as p,h as r,o}from"./vIpft52u.js";const n={class:"delivery-page"},b={class:"delivery-page__container"},a="Доставка — Indigo",t="Информация о самовывозе, сроках хранения, стоимости и вопросах по доставке.",f={__name:"delivery",setup(g){const s=[{label:"Главная",to:"/"},{label:"Правовая информация",to:"/legal-information"},{label:"Доставка",to:""}];return i({title:a,description:t,ogTitle:a,ogDescription:t}),(y,e)=>{const c=l;return o(),_("main",n,[v("div",b,[p(c,{items:s,class:"delivery-page__breadcrumbs"}),e[0]||(e[0]=r('<article class="delivery-page__card" data-v-c4f431b1><h1 class="delivery-page__title" data-v-c4f431b1> Доставка </h1><div class="delivery-page__content" data-v-c4f431b1><section class="delivery-page__section" data-v-c4f431b1><h2 class="delivery-page__h2" data-v-c4f431b1> Способы получения заказа </h2><div class="delivery-page__subsection" data-v-c4f431b1><h3 class="delivery-page__h3" data-v-c4f431b1> Самовывоз </h3><p class="delivery-page__text" data-v-c4f431b1> Заберите заказ по адресу: РФ, ДНР. Донецкий г.о., г. Донецк, ул. Постышева, д.60 </p><p class="delivery-page__text" data-v-c4f431b1> График работы пункта выдачи: Понедельник-Пятница с 09.00 до 18:00, Суббота и Воскресение -выходной </p><p class="delivery-page__text" data-v-c4f431b1> Как это работает: вы оформляете заказ → мы собираем его и отправляем уведомление о готовности на email и по SMS → вы приезжаете и забираете заказ. </p><p class="delivery-page__text" data-v-c4f431b1> Срок сборки заказа — указывается при оформлении заказа и подтверждается менеджером по телефону. Точный срок зависит от наличия товара на складе и отображается при оформлении заказа. </p></div></section><section class="delivery-page__section" data-v-c4f431b1><h2 class="delivery-page__h2" data-v-c4f431b1> Срок хранения заказа </h2><p class="delivery-page__text" data-v-c4f431b1> Готовый заказ хранится в пункте выдачи 14 календарных дней с момента уведомления о готовности. Если заказ не забран в этот срок, мы свяжемся с вами для уточнения. Невостребованный заказ отменяется, оплата не возвращается так как заказ изготовлен с индивидуальными характеристиками. </p></section><section class="delivery-page__section" data-v-c4f431b1><h2 class="delivery-page__h2" data-v-c4f431b1> Что взять с собой </h2><p class="delivery-page__text" data-v-c4f431b1> Для получения заказа назовите номер заказа. При оплате через СБП заказ уже оплачен — вам остаётся только забрать его. При безналичном расчёте убедитесь, что оплата поступила (статус заказа — «оплачен»). </p><p class="delivery-page__text" data-v-c4f431b1> При получении проверьте комплектность и внешний вид товара в присутствии сотрудника пункта выдачи. После подписания акта приёма-передачи претензии по комплектности не принимаются. </p></section><section class="delivery-page__section" data-v-c4f431b1><h2 class="delivery-page__h2" data-v-c4f431b1> Стоимость </h2><p class="delivery-page__text" data-v-c4f431b1> Самовывоз — бесплатно. </p></section><section class="delivery-page__section" data-v-c4f431b1><h2 class="delivery-page__h2" data-v-c4f431b1> География </h2><p class="delivery-page__text" data-v-c4f431b1> Пункт выдачи расположен по адресу: РФ, ДНР. Донецкий г.о., г. Донецк, ул. Постышева, д.60 <br data-v-c4f431b1> https://yandex.ru/profile/22215369024?lang=ru </p><div class="delivery-page__map" data-v-c4f431b1><span class="delivery-page__map-label" data-v-c4f431b1>карта</span></div></section><section class="delivery-page__section" data-v-c4f431b1><h2 class="delivery-page__h2" data-v-c4f431b1> Расширение способов доставки </h2><p class="delivery-page__text" data-v-c4f431b1> Актуальные способы получения заказа указаны на этой странице. По мере развития магазина мы будем добавлять новые варианты доставки. </p></section><section class="delivery-page__section" data-v-c4f431b1><h2 class="delivery-page__h2" data-v-c4f431b1> Вопросы по доставке </h2><p class="delivery-page__text" data-v-c4f431b1> Если заказ не готов в указанный срок или вам нужно изменить способ получения — свяжитесь с нами: <br data-v-c4f431b1> Тел.: +7 949-499-69-79, <br data-v-c4f431b1> E-mail: info@indigo-mail.ru </p></section></div></article>',1))])])}}},x=d(f,[["__scopeId","data-v-c4f431b1"]]);export{x as default};
